do_op <- function(so_far, op, x){
  if (op == "") {
    so_far = so_far + as.numeric(x)
  } else if (op == 'add') {
    so_far = so_far + as.numeric(x)
  } else if (op == 'mlt') {
    so_far = so_far * as.numeric(x)
  }
  return(so_far)
}
