```{.r .cell-code}
eval_equation <- function(eq) {
  # inititate total
  so_far = 0
  op = ""
  while (e < nchar(eq)) {
    e <<- e + 1
    x = substr(eq, e, e)

    # print(e)
    # print(x)

    if (x == " ") {
      # skip

    } else if (x == "(") {
      # recursion
      # print('recursion')
      rec = eval_equation(eq)
      so_far = do_op(so_far, op, rec)

    } else if (x == ")") {
      # close the recursion
      # return inside total
      # print('return')
      return(so_far)

    } else if (x == "+") {
      # add
      # print('add')
      op = 'add'

    } else if (x == "*") {
      # multiply
      # print('multiply')
      op = 'mlt'

    } else {
      # trusting that this is a number
      # print(x)
      so_far = do_op(so_far, op, x)
    }
    # print(so_far)
    # print('---')
  }
  return(so_far)
}
```
